var e=[{id:`L3_1`,type:`dialog`,speaker:`DAIN_GAMECIRCLE_NULL_NULL`,text:{KOREA:`와아, 진짜 움직이잖아!`,JPN:`わあ、本当に動いてる！`,ENG:`Wow, it’s really moving!`,TWN:`哇，真的會動欸！`},stage:{bg:`BLACK`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:{char_id:`DAIN_GAMECIRCLE_NULL_NULL`,face:`UNIT_LAUGH`}}}},{id:`L4_1`,type:`dialog`,speaker:`DAIN_GAMECIRCLE_NULL_NULL`,text:{KOREA:`저 리듬 타는 것 좀 봐, 리네가 건들거리는 것 같아서 너무 귀여워!`,JPN:`リズムに乗ってる姿、マリちゃんがゆらゆらしてるみたいで、すっごくかわいい！`,ENG:`Look at her grooving along the rhythm. It’s like the real Rinae when she swaggers!`,TWN:`好生動喔，璃奈還會搖欸，真可愛！`},stage:{bg:`BLACK`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:{char_id:`DAIN_GAMECIRCLE_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L6_1`,type:`dialog`,speaker:`STAR_GAMECIRCLE_NULL_NULL`,text:{KOREA:`건, 건들거리긴 누가 건들거린다고!`,JPN:`だ、誰がゆらゆらしとんねん！`,ENG:`S-swagger? I ain’t swaggerin’, no ma'am!`,TWN:`搖…什麼搖，我才沒有搖呢！`},stage:{bg:`BLACK`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`STAR_GAMECIRCLE_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`DAIN_GAMECIRCLE_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L7_1`,type:`dialog`,speaker:`STAR_GAMECIRCLE_NULL_NULL`,text:{KOREA:`와, 근데 진짜 점마 내랑 똑같이 생겼네.`,JPN:`うわ、でも本当にウチとそっくりやわ。`,ENG:`But oh my, it does really look like me, don’t it?`,TWN:`哇，不過長得真的和我一模一樣的唄！`},stage:{bg:`BLACK`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`STAR_GAMECIRCLE_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`DAIN_GAMECIRCLE_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L8_1`,type:`dialog`,speaker:`STAR_GAMECIRCLE_NULL_NULL`,text:{KOREA:`쪼끄만 미리네 같아가 진짜 신기하네! 마음에 쏙 든다!`,JPN:`小っちゃいマリっぽくて、めっちゃ不思議やな！　気に入ったわ！`,ENG:`It’s like a tiny Rinae! I love it!`,TWN:`小小的宓璃奈好奇妙喔！我喜歡！`},stage:{bg:`BLACK`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`STAR_GAMECIRCLE_NULL_NULL`,face:`UNIT_LAUGH`},C:null,R:{char_id:`DAIN_GAMECIRCLE_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L11_1`,type:`dialog`,speaker:`BOX_NPC_GAMECIRCLE_NULL`,text:{KOREA:`아, 아하하. 마음에 든다니 다행이네요.`,JPN:`あ、あはは。気に入ってもらえてよかったです。`,ENG:`A-ah ha ha. I’m glad you like it.`,TWN:`哈，哈哈，幸好你喜歡。`},stage:{bg:`BLACK`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`STAR_GAMECIRCLE_NULL_NULL`,face:`UNIT_LAUGH`},C:null,R:{char_id:`BOX_NPC_GAMECIRCLE_NULL`,face:`UNIT_SERIOUS2`}}}},{id:`L12_1`,type:`dialog`,speaker:`STAR_GAMECIRCLE_NULL_NULL`,text:{KOREA:`헤헷. 마, 박스. 니 진짜 천재가? 천재 맞제? 나만의 캐릭터라니 기분 직이네! 헤헤.`,JPN:`へへっ。なあ、ダンボール。あんた、ホンマに天才やな？　天才やで？　自分のキャラって、めちゃくちゃ気分ええんやけど！　へへ。`,ENG:`Heh. Hey, Box. Ya really are somethin’, aren’t ya? Ya made me into a character! I’m havin’ a hoot!`,TWN:`嘿嘿，紙箱，你是天才！是唄？是我的專屬角色欸，超開心！嘿嘿～`},stage:{bg:`BLACK`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`STAR_GAMECIRCLE_NULL_NULL`,face:`UNIT_LAUGH`},C:null,R:{char_id:`BOX_NPC_GAMECIRCLE_NULL`,face:`UNIT_SERIOUS2`}}}},{id:`L13_1`,type:`dialog`,speaker:`BOX_NPC_GAMECIRCLE_NULL`,text:{KOREA:`이, 이렇게까지 좋아할 줄은 몰랐는데…….`,JPN:`こ、ここまで喜ぶとは思ってもいませんでした……`,ENG:`I-I didn’t know it would mean that much to you...`,TWN:`沒…沒想到你會開心成這樣……`},stage:{bg:`BLACK`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`STAR_GAMECIRCLE_NULL_NULL`,face:`UNIT_LAUGH`},C:null,R:{char_id:`BOX_NPC_GAMECIRCLE_NULL`,face:`UNIT_SERIOUS2`}}}}];export{e as default};